import{_ as a,o as l,c as e,a2 as r}from"./chunks/framework.CW5cCyjm.js";const u=JSON.parse('{"title":"数据库规范","description":"","frontmatter":{},"headers":[],"relativePath":"mango-pmo/rules/backend/04-db.md","filePath":"mango-pmo/rules/backend/04-db.md"}'),o={name:"mango-pmo/rules/backend/04-db.md"};function t(n,i,d,s,h,c){return l(),e("div",null,[...i[0]||(i[0]=[r('<h1 id="数据库规范" tabindex="-1">数据库规范 <a class="header-anchor" href="#数据库规范" aria-label="Permalink to &quot;数据库规范&quot;">​</a></h1><h2 id="_1-表规则" tabindex="-1">1. 表规则 <a class="header-anchor" href="#_1-表规则" aria-label="Permalink to &quot;1. 表规则&quot;">​</a></h2><ul><li>表名使用小写下划线。</li><li>表名必须体现模块边界。</li><li>不使用外键作为默认方案。</li><li>一个表只服务一个领域。</li></ul><h2 id="_2-字段规则" tabindex="-1">2. 字段规则 <a class="header-anchor" href="#_2-字段规则" aria-label="Permalink to &quot;2. 字段规则&quot;">​</a></h2><ul><li>字段名使用小写下划线。</li><li>字段类型按真实业务选择。</li><li>公共审计字段按项目基线统一。</li><li>多租户表按需要增加 <code>tenant_id</code>。</li></ul><h2 id="_3-索引规则" tabindex="-1">3. 索引规则 <a class="header-anchor" href="#_3-索引规则" aria-label="Permalink to &quot;3. 索引规则&quot;">​</a></h2><ul><li>索引只为明确查询场景服务。</li><li>不创建无效索引和重复索引。</li><li>联合索引按查询条件设计。</li><li>不在低区分度字段上滥建索引。</li></ul><h2 id="_4-sql-规则" tabindex="-1">4. SQL 规则 <a class="header-anchor" href="#_4-sql-规则" aria-label="Permalink to &quot;4. SQL 规则&quot;">​</a></h2><ul><li>必须使用参数化查询。</li><li>禁止字符串拼接 SQL。</li><li>Mapper 只访问本域表。</li><li>跨域数据通过 API 获取。</li></ul><h2 id="_5-迁移规则" tabindex="-1">5. 迁移规则 <a class="header-anchor" href="#_5-迁移规则" aria-label="Permalink to &quot;5. 迁移规则&quot;">​</a></h2><ul><li>所有 DDL 变更必须使用 Flyway migration。</li><li>只新增 migration，不修改历史 migration。</li><li>migration 按模块隔离。</li><li>migration 命名使用 <code>V{version}__{description}.sql</code>。</li></ul><h2 id="_6-初始化数据规则" tabindex="-1">6. 初始化数据规则 <a class="header-anchor" href="#_6-初始化数据规则" aria-label="Permalink to &quot;6. 初始化数据规则&quot;">​</a></h2><ul><li>系统菜单、权限、公共路径、字典、租户默认数据、业务状态、流程配置、计费规则等需要持久化或运营的数据，必须通过 migration、后台维护入口或配置中心提供。</li><li>菜单、按钮权限、菜单运行时配置、菜单套餐授权和默认角色授权默认数据，必须通过 Resource Registry 的 <code>AUTH_MENU</code> 资源注入，禁止用 Flyway SQL 维护。</li><li>未发布前允许重整初始化 SQL；发布后只能新增 migration，不修改已执行历史 migration。</li><li>初始化数据必须明确租户边界：全局数据、租户默认数据和租户私有数据不得混用。</li><li>接口不得用硬编码数据替代应入库的数据。</li></ul><h2 id="_7-禁止事项" tabindex="-1">7. 禁止事项 <a class="header-anchor" href="#_7-禁止事项" aria-label="Permalink to &quot;7. 禁止事项&quot;">​</a></h2><ul><li>直接改生产库</li><li>在 Mapper 中跨域 join</li><li>表结构变更没有 migration</li><li>应入库数据写死在接口、前端页面、测试替身或配置样例中作为最终交付</li></ul>',15)])])}const m=a(o,[["render",t]]);export{u as __pageData,m as default};
